     2→import type { ParameterPointsProgramResponse, ParameterPointsProgramValue } from '../models';
     3→
     4→interface CategoryItem {
     5→  category: string;
     6→  questions?: Array<{
     7→    question: string;
     8→    answer: string;
     9→  }>;
    10→  icon?: string;
    11→  order?: number;
    12→}
    13→
    14→interface ParsedData {
    15→  categories: CategoryItem[];
    16→}
    17→
    18→export function mapParameterPointsProgramResponse(
    19→  response: ParameterPointsProgramResponse[]
    20→): ParameterPointsProgramResponse[] {
    21→  try {
    22→    const find = response.find((item) => item.category.toLowerCase() === 'saiba mais');
    23→
    24→    if (!find || typeof find.value !== 'string') {
    25→      return [];
    26→    }
    27→
    28→    const data = JSON.parse(find.value) as ParsedData;
    29→
    30→    if (!data?.categories || !Array.isArray(data.categories)) {
    31→      return [];
    32→    }
    33→
    34→    return data.categories.map((item, index): ParameterPointsProgramResponse => {
    35→      const value: ParameterPointsProgramValue = {
    36→        questions: item.questions ?? [],
    37→        order: item.order ?? index,
    38→        icon: (item.icon as PropsIconsNameCore) ?? 'icon-help',
    39→      };
    40→
    41→      return {
    42→        category: item.category,
    43→        value,
    44→        dateCreated: find.dateCreated,
    45→        status: find.status,
    46→        PK: find.PK,
    47→        dateUpdated: find.dateUpdated,
    48→      };
    49→    });
    50→  } catch {
    51→    return [];
    52→  }
    53→}
